 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 5	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Button, ButtonVariant } from '@patternfly/react-core';
 8	
 9	import { ACTIVATION_KEYS_DOCUMENTATION_URL, ACTIVATION_KEYS_URL } from '../../utils/constants';
10	
11	const ActivationKeyHelpIcon: FC = () => {
12	  const { t } = useKubevirtTranslation();
13	  return (
14	    <HelpTextIcon
15	      bodyContent={
16	        <>
17	          <Trans ns="plugin__kubevirt-plugin" t={t}>
18	            An activation key is a preshared authentication token that enables authorized users to
19	            register and configure systems. Organization administrators can browse to{' '}
20	            <Button
21	              component="a"
22	              href={ACTIVATION_KEYS_URL}
23	              isInline
24	              target="_blank"
25	              variant={ButtonVariant.link}
26	            >
27	              Activation keys
28	            </Button>{' '}
29	            to track an existing Activation key or use the Create activation key button to create a
30	            new one.
31	          </Trans>
32	          <br />
33	          <br />
34	          <ExternalLink href={ACTIVATION_KEYS_DOCUMENTATION_URL} text={t('Read more')} />
35	        </>
36	      }
37	    />
38	  );
39	};
40	
41	export default ActivationKeyHelpIcon;

